"use client";

import appIcon from "../../../../assets/icon.png";

import {
  Globe,
  House,
  LayoutGrid,
  Menu,
  Search,
  ShoppingBag,
  UserCircle2,
  X,
  type LucideIcon,
} from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import {
  useDeferredValue,
  useEffect,
  useState,
  useTransition,
  type FormEvent,
} from "react";

import { useStorefront } from "@/components/providers/StorefrontProvider";
import { useSupabaseSession } from "@/components/providers/SupabaseSessionProvider";
import { cn } from "@/lib/utils";
import { useCartStore } from "@/store/cart";

type NavLinkItem = {
  href: string;
  key: string;
  icon: LucideIcon;
};

type HeaderSearchProps = {
  value: string;
  isRTL: boolean;
  placeholder: string;
  helperText: string | null;
  pending: boolean;
  onChange: (value: string) => void;
  onClear: () => void;
  onSubmit: (event: FormEvent<HTMLFormElement>) => void;
};

const NAV_LINKS: NavLinkItem[] = [
  { href: "/", key: "nav.home", icon: House },
  { href: "/products", key: "nav.products", icon: LayoutGrid },
];

const actionButtonClass =
  "inline-flex h-11 w-11 items-center justify-center rounded-[1.15rem] border border-slate-200/80 bg-white/95 text-slate-700 transition duration-200 hover:-translate-y-0.5 hover:border-primary/30 hover:text-[#1D1D1F] hover:shadow-soft";

function isNavActive(pathname: string, href: string) {
  if (href === "/") {
    return pathname === "/";
  }

  if (href === "/products") {
    return (
      pathname === "/products" ||
      pathname.startsWith("/product/") ||
      pathname.startsWith("/category/")
    );
  }

  return pathname === href;
}

function HeaderSearch({
  value,
  isRTL,
  placeholder,
  helperText,
  pending,
  onChange,
  onClear,
  onSubmit,
}: HeaderSearchProps) {
  const hasValue = value.trim().length > 0;
  const clearLabel = isRTL ? "مسح البحث" : "Clear search";
  const submitLabel = isRTL ? "بحث" : "Search";

  return (
    <form onSubmit={onSubmit} className="w-full">
      <div className="rounded-[1.55rem] border border-white/80 bg-white/92 p-1.5 shadow-soft">
        <div className="flex items-center gap-2">
          <div className="relative min-w-0 flex-1">
            <Search
              size={17}
              className={cn(
                "pointer-events-none absolute top-1/2 -translate-y-1/2 text-slate-400",
                isRTL ? "right-4" : "left-4"
              )}
            />
            <input
              type="search"
              name="q"
              value={value}
              onChange={(event) => onChange(event.target.value)}
              placeholder={placeholder}
              autoComplete="off"
              className={cn(
                "h-11 w-full rounded-[1.1rem] border-0 bg-transparent text-sm text-[#1D1D1F] outline-none placeholder:text-slate-400",
                hasValue
                  ? isRTL
                    ? "pl-10 pr-11 text-right"
                    : "pl-11 pr-10 text-left"
                  : isRTL
                    ? "pr-11 text-right"
                    : "pl-11 text-left"
              )}
            />
            {hasValue ? (
              <button
                type="button"
                onClick={onClear}
                className={cn(
                  "absolute top-1/2 inline-flex h-7 w-7 -translate-y-1/2 items-center justify-center rounded-full text-slate-400 transition hover:bg-slate-100 hover:text-slate-700",
                  isRTL ? "left-2" : "right-2"
                )}
                aria-label={clearLabel}
                title={clearLabel}
              >
                <X size={15} />
              </button>
            ) : null}
          </div>

          <button
            type="submit"
            className="inline-flex h-11 shrink-0 items-center justify-center gap-2 rounded-[1.1rem] bg-[#1D1D1F] px-4 text-sm font-medium text-white shadow-button transition hover:bg-primary"
            aria-label={submitLabel}
            title={submitLabel}
          >
            <Search size={16} />
            <span className="hidden sm:inline">{submitLabel}</span>
          </button>
        </div>
      </div>

      {helperText ? (
        <p
          className={cn(
            "mt-2 px-1 text-xs",
            pending ? "text-primary" : "text-slate-500",
            isRTL ? "text-right" : "text-left"
          )}
        >
          {helperText}
        </p>
      ) : null}
    </form>
  );
}

export function Header() {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const { user } = useSupabaseSession();
  const { isRTL, language, t, toggleLanguage } = useStorefront();
  const totalItems = useCartStore((state) => state.totalItems);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const currentQuery = searchParams.get("q") ?? "";
  const [searchValue, setSearchValue] = useState(currentQuery);
  const deferredSearchValue = useDeferredValue(searchValue);
  const [isSearchPending, startSearchTransition] = useTransition();

  const cartActive = pathname === "/cart";
  const accountActive =
    pathname.startsWith("/account") || pathname.startsWith("/auth");
  const trimmedSearch = searchValue.trim();
  const searchHelperText = isSearchPending
    ? language === "ar"
      ? "جارٍ تحديث البحث..."
      : "Updating search..."
    : trimmedSearch
      ? language === "ar"
        ? `اضغط Enter للبحث عن "${trimmedSearch}"`
        : `Press Enter to search for "${trimmedSearch}"`
      : null;
  const languageTitle = language === "ar" ? "العربية" : "English";
  const languageActionLabel =
    language === "ar" ? "التبديل إلى الإنجليزية" : "Switch to Arabic";
  const accountLabel = user ? t("nav.account") : t("nav.login");

  useEffect(() => {
    setSearchValue(currentQuery);
  }, [currentQuery]);

  useEffect(() => {
    if (pathname !== "/products") {
      return;
    }

    const normalized = deferredSearchValue.trim();

    if (normalized === currentQuery) {
      return;
    }

    const params = new URLSearchParams(searchParams.toString());

    if (normalized) {
      params.set("q", normalized);
    } else {
      params.delete("q");
    }

    const query = params.toString();

    startSearchTransition(() => {
      router.replace(query ? `${pathname}?${query}` : pathname, {
        scroll: false,
      });
    });
  }, [
    currentQuery,
    deferredSearchValue,
    pathname,
    router,
    searchParams,
    startSearchTransition,
  ]);

  function buildSearchHref(value: string) {
    const normalized = value.trim();
    const params =
      pathname === "/products"
        ? new URLSearchParams(searchParams.toString())
        : new URLSearchParams();

    if (normalized) {
      params.set("q", normalized);
    } else {
      params.delete("q");
    }

    const query = params.toString();
    return query ? `/products?${query}` : "/products";
  }

  function submitSearch(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setIsMenuOpen(false);

    startSearchTransition(() => {
      router.push(buildSearchHref(searchValue));
    });
  }

  function clearSearch() {
    setSearchValue("");

    if (pathname === "/products") {
      startSearchTransition(() => {
        router.replace(buildSearchHref(""), { scroll: false });
      });
    }
  }

  function changeLanguage() {
    toggleLanguage();
    setIsMenuOpen(false);
    router.refresh();
  }

  return (
    <header className="sticky top-0 z-50 px-4 pt-3 sm:px-6 sm:pt-4 lg:px-8">
      <div className="mx-auto w-full max-w-7xl">
        <div className="relative overflow-hidden rounded-[1.9rem] border border-white/80 bg-white/70 px-3 py-3 shadow-soft backdrop-blur-2xl sm:px-4 lg:px-5">
          <div className="pointer-events-none absolute inset-x-10 top-0 h-20 bg-[radial-gradient(circle_at_top,rgba(46,125,50,0.14),rgba(255,179,0,0.06)_42%,transparent_74%)] blur-3xl" />

          <div className="relative space-y-3">
            <div className="flex items-center justify-between gap-3">
              <div
                className={cn(
                  "flex min-w-0 items-center gap-3",
                  isRTL && "flex-row-reverse"
                )}
              >
                <button
                  type="button"
                  onClick={() => setIsMenuOpen((current) => !current)}
                  className={cn(actionButtonClass, "lg:hidden")}
                  aria-label={t("nav.menu")}
                  aria-expanded={isMenuOpen}
                  title={t("nav.menu")}
                >
                  {isMenuOpen ? <X size={18} /> : <Menu size={18} />}
                </button>

                <Link
                  href="/"
                  className={cn(
                    "inline-flex min-w-0 items-center gap-3 rounded-[1.3rem] border border-white/80 bg-white/95 px-3 py-2 shadow-soft transition duration-200 hover:-translate-y-0.5 hover:shadow-premium",
                    isRTL && "flex-row-reverse"
                  )}
                >
                  <span className="relative h-9 w-9 shrink-0 overflow-hidden rounded-full border border-slate-200 bg-white shadow-sm">
                    <Image
                      src={appIcon}
                      alt="الأمل سنتر"
                      fill
                      priority
                      sizes="36px"
                      className="object-cover scale-[1.9]"
                    />
                  </span>
                  <span className="min-w-0 truncate text-sm font-semibold text-[#1D1D1F] sm:text-base">
                    الأمل سنتر
                  </span>
                </Link>
              </div>

              <div className="hidden min-w-0 flex-1 px-2 lg:block">
                <div className="mx-auto w-full max-w-[42rem]">
                  <HeaderSearch
                    value={searchValue}
                    isRTL={isRTL}
                    placeholder={t("nav.search")}
                    helperText={searchHelperText}
                    pending={isSearchPending}
                    onChange={setSearchValue}
                    onClear={clearSearch}
                    onSubmit={submitSearch}
                  />
                </div>
              </div>

              <div
                className={cn(
                  "flex shrink-0 items-center gap-2",
                  isRTL && "flex-row-reverse"
                )}
              >
                <nav
                  className={cn(
                    "hidden items-center gap-2 lg:flex",
                    isRTL && "flex-row-reverse"
                  )}
                >
                  {NAV_LINKS.map((item) => {
                    const Icon = item.icon;
                    const active = isNavActive(pathname, item.href);

                    return (
                      <Link
                        key={item.href}
                        href={item.href}
                        aria-current={active ? "page" : undefined}
                        className={cn(
                          "inline-flex h-11 items-center gap-2 rounded-[1.1rem] border px-3 text-sm font-medium transition",
                          active
                            ? "border-[#1D1D1F] bg-[#1D1D1F] text-white shadow-soft"
                            : "border-slate-200/80 bg-white/95 text-slate-600 hover:border-primary/30 hover:text-[#1D1D1F]"
                        )}
                        title={t(item.key)}
                      >
                        <Icon size={17} />
                        <span className="hidden xl:inline">{t(item.key)}</span>
                      </Link>
                    );
                  })}
                </nav>

                <button
                  type="button"
                  onClick={changeLanguage}
                  className={actionButtonClass}
                  aria-label={languageActionLabel}
                  title={languageTitle}
                >
                  <Globe size={17} />
                </button>

                <Link
                  href={user ? "/account" : "/auth/login"}
                  className={cn(
                    actionButtonClass,
                    user
                      ? "border-primary/25 bg-primary/10 text-primary"
                      : accountActive
                        ? "border-slate-300 bg-slate-100 text-slate-900"
                        : ""
                  )}
                  aria-label={accountLabel}
                  title={t("nav.account")}
                >
                  <UserCircle2 size={18} />
                </Link>

                <Link
                  href="/cart"
                  className={cn(
                    "relative inline-flex h-11 w-11 items-center justify-center rounded-[1.15rem] border bg-white/95 transition duration-200 hover:-translate-y-0.5 hover:shadow-soft",
                    cartActive
                      ? "border-primary/30 bg-primary/5 text-primary"
                      : "border-slate-200/80 text-slate-700 hover:border-primary/30 hover:text-[#1D1D1F]"
                  )}
                  aria-label={t("nav.cart")}
                  title={t("nav.cart")}
                >
                  <ShoppingBag size={18} />
                  <span
                    className={cn(
                      "absolute -top-1 min-w-5 rounded-full bg-primary px-1.5 py-0.5 text-center text-[11px] font-bold text-white",
                      isRTL ? "-left-1" : "-right-1"
                    )}
                  >
                    {totalItems}
                  </span>
                </Link>
              </div>
            </div>

            <div className="lg:hidden">
              <HeaderSearch
                value={searchValue}
                isRTL={isRTL}
                placeholder={t("nav.search")}
                helperText={searchHelperText}
                pending={isSearchPending}
                onChange={setSearchValue}
                onClear={clearSearch}
                onSubmit={submitSearch}
              />
            </div>

            <div
              className={cn(
                "overflow-hidden transition-[max-height,opacity,margin] duration-300 lg:hidden",
                isMenuOpen ? "max-h-60 opacity-100" : "max-h-0 opacity-0"
              )}
            >
              <div className="grid gap-2 border-t border-slate-100 pt-3">
                {NAV_LINKS.map((item) => {
                  const Icon = item.icon;
                  const active = isNavActive(pathname, item.href);

                  return (
                    <Link
                      key={item.href}
                      href={item.href}
                      onClick={() => setIsMenuOpen(false)}
                      className={cn(
                        "flex min-h-11 items-center gap-3 rounded-[1.2rem] border px-4 text-sm font-medium transition",
                        isRTL && "flex-row-reverse",
                        active
                          ? "border-primary/30 bg-primary/5 text-primary"
                          : "border-slate-200/80 bg-white/95 text-slate-600 hover:border-primary/30 hover:text-[#1D1D1F]"
                      )}
                    >
                      <Icon size={17} />
                      <span>{t(item.key)}</span>
                    </Link>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </div>
    </header>
  );
}
